import{_ as e,c as a,o as i,a as t}from"./app.87b1f767.js";const f=JSON.parse('{"title":"方法的重写","description":"","frontmatter":{},"headers":[{"level":2,"title":"为什么需要方法的重写","slug":"为什么需要方法的重写","link":"#为什么需要方法的重写","children":[]},{"level":2,"title":"方法的重写和方法的重载之间的区别","slug":"方法的重写和方法的重载之间的区别","link":"#方法的重写和方法的重载之间的区别","children":[]}],"relativePath":"java/basis/index11.md"}'),l={name:"java/basis/index11.md"},r=t('<h1 id="方法的重写" tabindex="-1">方法的重写 <a class="header-anchor" href="#方法的重写" aria-hidden="true">#</a></h1><ul><li>子父类中出现了一模一样的方法</li><li>重新是一种现象，也是一个动作</li><li>当子类需要父类的功能，而功能主体子类有自己特有的内容时，可以重写父类的方法，这样即延续了父类的功能，又定义了子类特有的内容</li></ul><h2 id="为什么需要方法的重写" tabindex="-1">为什么需要方法的重写 <a class="header-anchor" href="#为什么需要方法的重写" aria-hidden="true">#</a></h2><p>当子类继承父类时，父类的方法不使用子类，于是子类重新父类方法</p><h2 id="方法的重写和方法的重载之间的区别" tabindex="-1">方法的重写和方法的重载之间的区别 <a class="header-anchor" href="#方法的重写和方法的重载之间的区别" aria-hidden="true">#</a></h2><ul><li>方法重载：方法名相同，参数列表不同，根返回值和权限修饰符无关</li><li>方法重写：子类要去覆盖掉父类的方法，就要防止失误，把覆盖变成重载的失误</li><li>子类重写的方法名、参数列表、返回值类型必须和父类一样，且访问权限修饰符不能小于父类</li></ul>',6),n=[r];function s(d,c,_,h,o,u){return i(),a("div",null,n)}const x=e(l,[["render",s]]);export{f as __pageData,x as default};
